      {"title": "CREATE TABLE & Data Types", "theory": "## CREATE TABLE\n```python\n# SQLite in Python simulates SQL perfectly\nimport sqlite3\nconn = sqlite3.connect(':memory:')\ncursor = conn.cursor()\n\ncursor.execute('''\n    CREATE TABLE students (\n        id INTEGER PRIMARY KEY,\n        name TEXT NOT NULL,\n        email TEXT UNIQUE,\n        score REAL DEFAULT 0.0,\n        enrolled BOOLEAN DEFAULT 1\n    )\n''')\n```\nCommon types: INTEGER, TEXT, REAL, BOOLEAN, BLOB", "instructions": "## Task: Create Academy Tables\n1. Create a `courses` table with: id, title, level, max_students\n2. Create an `enrollments` table with: id, student_name, course_id, grade\n3. Insert 3 courses and 4 enrollments\n4. Query and print all data", "starterCode": "import sqlite3\nconn = sqlite3.connect(':memory:')\nc = conn.cursor()\n\nc.execute('''CREATE TABLE courses (\n    id INTEGER PRIMARY KEY,\n    title TEXT NOT ___,\n    level TEXT DEFAULT 'Beginner',\n    max_students INTEGER DEFAULT ___\n)''')\n\nc.execute('''CREATE TABLE enrollments (\n    id INTEGER PRIMARY KEY,\n    student_name TEXT NOT NULL,\n    course_id INTEGER,\n    grade TEXT DEFAULT ___\n)''')\n\n# Insert courses\nc.execute(\"INSERT INTO courses (title, level) VALUES ('Python', 'Beginner')\")\nc.execute(\"INSERT INTO courses (title, level) VALUES ('SQL', 'Intermediate')\")\nc.execute(\"INSERT INTO courses (title, level) VALUES ('AI', '___')\")\n\n# Insert enrollments\nc.execute(\"INSERT INTO enrollments (student_name, course_id) VALUES ('Ada', 1)\")\nc.execute(\"INSERT INTO enrollments (student_name, course_id) VALUES ('Tunde', ___)\")\nc.execute(\"INSERT INTO enrollments (student_name, course_id, grade) VALUES ('Ngozi', 1, 'A')\")\nc.execute(\"INSERT INTO enrollments (student_name, course_id, grade) VALUES ('Kemi', 3, '___')\")\n\nconn.commit()\n\nprint('=== Courses ===')\nfor row in c.execute('SELECT * FROM courses'):\n    print(row)\nprint('\\n=== Enrollments ===')\nfor row in c.execute('SELECT * FROM enrollments'):\n    print(row)", "solution": "import sqlite3\nconn=sqlite3.connect(':memory:')\nc=conn.cursor()\nc.execute('''CREATE TABLE courses(id INTEGER PRIMARY KEY,title TEXT NOT NULL,level TEXT DEFAULT 'Beginner',max_students INTEGER DEFAULT 30)''')\nc.execute('''CREATE TABLE enrollments(id INTEGER PRIMARY KEY,student_name TEXT NOT NULL,course_id INTEGER,grade TEXT DEFAULT 'N/A')''')\nc.execute(\"INSERT INTO courses(title,level)VALUES('Python','Beginner')\")\nc.execute(\"INSERT INTO courses(title,level)VALUES('SQL','Intermediate')\")\nc.execute(\"INSERT INTO courses(title,level)VALUES('AI','Advanced')\")\nc.execute(\"INSERT INTO enrollments(student_name,course_id)VALUES('Ada',1)\")\nc.execute(\"INSERT INTO enrollments(student_name,course_id)VALUES('Tunde',2)\")\nc.execute(\"INSERT INTO enrollments(student_name,course_id,grade)VALUES('Ngozi',1,'A')\")\nc.execute(\"INSERT INTO enrollments(student_name,course_id,grade)VALUES('Kemi',3,'B')\")\nconn.commit()\nprint('=== Courses ===')\nfor row in c.execute('SELECT * FROM courses'):print(row)\nprint('\\n=== Enrollments ===')\nfor row in c.execute('SELECT * FROM enrollments'):print(row)", "hint": "NOT NULL prevents empty values. DEFAULT sets fallback. INTEGER PRIMARY KEY auto-increments.", "rubric": "Two tables created. NOT NULL and DEFAULT used. Data inserted. Query displays results."},
      {"title": "UPDATE & DELETE Operations", "theory": "## UPDATE & DELETE\n```python\n# UPDATE specific rows\ncursor.execute('''\n    UPDATE students SET score = 95\n    WHERE name = 'Ada'\n''')\n\n# UPDATE with calculation\ncursor.execute('''\n    UPDATE students SET score = score + 10\n    WHERE score < 50\n''')\n\n# DELETE specific rows\ncursor.execute('''\n    DELETE FROM students WHERE score < 30\n''')\n\n# DELETE all (careful!)\ncursor.execute('DELETE FROM students')\n```", "instructions": "## Task: Student Management\n1. Create a students table and insert 5 students\n2. UPDATE: Give bonus 10 points to students scoring below 80\n3. UPDATE: Change level to 'Advanced' for scores >= 90\n4. DELETE: Remove students with score below 50\n5. Print before and after", "starterCode": "import sqlite3\nconn = sqlite3.connect(':memory:')\nc = conn.cursor()\n\nc.execute('CREATE TABLE students (id INTEGER PRIMARY KEY, name TEXT, score INTEGER, level TEXT DEFAULT \"Beginner\")')\n\nfor name, score in [('Ada',92),('Tunde',45),('Ngozi',78),('Kemi',88),('Bayo',35)]:\n    c.execute('INSERT INTO students (name,score) VALUES (?,?)', (name, score))\nconn.commit()\n\nprint('=== BEFORE ===')\nfor row in c.execute('SELECT * FROM students'): print(row)\n\n# Bonus points\nc.execute('UPDATE students SET score = score + ___ WHERE score < ___')\n\n# Promote to Advanced\nc.execute('UPDATE students SET level = ___ WHERE score >= ___')\n\n# Remove failing students\nc.execute('DELETE FROM students WHERE score < ___')\nconn.commit()\n\nprint('\\n=== AFTER ===')\nfor row in c.execute('SELECT * FROM students'): print(row)", "solution": "import sqlite3\nconn=sqlite3.connect(':memory:')\nc=conn.cursor()\nc.execute('CREATE TABLE students(id INTEGER PRIMARY KEY,name TEXT,score INTEGER,level TEXT DEFAULT \"Beginner\")')\nfor name,score in [('Ada',92),('Tunde',45),('Ngozi',78),('Kemi',88),('Bayo',35)]:\n    c.execute('INSERT INTO students(name,score)VALUES(?,?)',(name,score))\nconn.commit()\nprint('=== BEFORE ===')\nfor row in c.execute('SELECT * FROM students'):print(row)\nc.execute('UPDATE students SET score=score+10 WHERE score<80')\nc.execute('UPDATE students SET level=\"Advanced\" WHERE score>=90')\nc.execute('DELETE FROM students WHERE score<50')\nconn.commit()\nprint('\\n=== AFTER ===')\nfor row in c.execute('SELECT * FROM students'):print(row)", "hint": "UPDATE...SET...WHERE for conditional updates. DELETE FROM...WHERE for removal.", "rubric": "Table created with data. UPDATE with bonus. UPDATE level. DELETE low scores. Before/after shown."},
      {"title": "WHERE Clauses & Operators", "theory": "## WHERE Operators\n```python\n# Comparison\nSELECT * FROM students WHERE score >= 80\n\n# AND / OR\nWHERE score >= 80 AND level = 'Advanced'\nWHERE course = 'Python' OR course = 'SQL'\n\n# IN\nWHERE course IN ('Python', 'SQL', 'AI')\n\n# BETWEEN\nWHERE score BETWEEN 70 AND 90\n\n# LIKE (pattern matching)\nWHERE name LIKE 'A%'     -- starts with A\nWHERE email LIKE '%@gmail.com'\n\n# IS NULL / IS NOT NULL\nWHERE grade IS NOT NULL\n```", "instructions": "## Task: Advanced Queries\n1. Create students with various attributes\n2. Query: students scoring BETWEEN 70 AND 90\n3. Query: students whose name starts with 'A' or 'N'\n4. Query: students in Python OR AI courses\n5. Query: students with no grade assigned (IS NULL)", "starterCode": "import sqlite3\nconn = sqlite3.connect(':memory:')\nc = conn.cursor()\n\nc.execute('CREATE TABLE students (name TEXT, course TEXT, score INTEGER, grade TEXT)')\ndata = [('Ada','Python',92,'A'),('Tunde','SQL',78,None),('Ngozi','AI',85,'B'),\n        ('Kemi','Python',70,None),('Bayo','AI',95,'A'),('Amara','SQL',62,None)]\nfor d in data:\n    c.execute('INSERT INTO students VALUES (?,?,?,?)', d)\nconn.commit()\n\nprint('=== Score 70-90 ===')\nfor r in c.execute('SELECT * FROM students WHERE score ___ 70 ___ 90'): print(r)\n\nprint('\\n=== Names starting with A or N ===')\nfor r in c.execute(\"SELECT * FROM students WHERE name LIKE '___' OR name LIKE '___'\"): print(r)\n\nprint('\\n=== Python or AI students ===')\nfor r in c.execute(\"SELECT * FROM students WHERE course ___ ('Python', 'AI')\"): print(r)\n\nprint('\\n=== No grade assigned ===')\nfor r in c.execute('SELECT * FROM students WHERE grade ___ ___'): print(r)", "solution": "import sqlite3\nconn=sqlite3.connect(':memory:')\nc=conn.cursor()\nc.execute('CREATE TABLE students(name TEXT,course TEXT,score INTEGER,grade TEXT)')\ndata=[('Ada','Python',92,'A'),('Tunde','SQL',78,None),('Ngozi','AI',85,'B'),('Kemi','Python',70,None),('Bayo','AI',95,'A'),('Amara','SQL',62,None)]\nfor d in data:c.execute('INSERT INTO students VALUES(?,?,?,?)',d)\nconn.commit()\nprint('=== Score 70-90 ===')\nfor r in c.execute('SELECT * FROM students WHERE score BETWEEN 70 AND 90'):print(r)\nprint('\\n=== Names starting with A or N ===')\nfor r in c.execute(\"SELECT * FROM students WHERE name LIKE 'A%' OR name LIKE 'N%'\"):print(r)\nprint('\\n=== Python or AI ===')\nfor r in c.execute(\"SELECT * FROM students WHERE course IN ('Python','AI')\"):print(r)\nprint('\\n=== No grade ===')\nfor r in c.execute('SELECT * FROM students WHERE grade IS NULL'):print(r)", "hint": "BETWEEN x AND y. LIKE 'A%' for starts with. IN (...) for list. IS NULL for empty.", "rubric": "BETWEEN used. LIKE with % wildcard. IN for list matching. IS NULL for null check."}
    ,
      {"title": "Semantic HTML & Structure", "theory": "## Semantic HTML\nSemantic elements describe their meaning to both browsers and developers.\n```python\n# Python string representing semantic HTML\nhtml = '''\n<header>Site title</header>\n<nav>Navigation links</nav>\n<main>\n  <article>\n    <h1>Article Title</h1>\n    <p>Content here</p>\n  </article>\n  <aside>Sidebar</aside>\n</main>\n<footer>Copyright info</footer>\n'''\n```\nKey elements: header, nav, main, article, section, aside, footer", "instructions": "## Task: Build a Page Structure\n1. Create an HTML string for a course page\n2. Use header, nav, main, article, and footer\n3. The article should have h1, h2, and paragraph tags\n4. Count the semantic elements used", "starterCode": "html = f'''\n<___>\n  <h1>Mabel Academy</h1>\n</___>\n<___>\n  <a href=\"/courses\">Courses</a>\n  <a href=\"/about\">About</a>\n</___>\n<___>\n  <___>\n    <h1>Python Fundamentals</h1>\n    <h2>Lesson 1: Variables</h2>\n    <p>Variables store data in memory.</p>\n  </___>\n</___>\n<___>\n  <p>Copyright 2024 Mabel Academy</p>\n</___>\n'''\n\n# Count semantic elements\nsemantic_tags = ['header', 'nav', 'main', 'article', 'footer']\ncount = sum(1 for tag in semantic_tags if f'<{tag}>' in html)\nprint(f'Semantic elements used: {count}/{len(semantic_tags)}')\nprint(html)", "solution": "html=f'''\n<header>\n  <h1>Mabel Academy</h1>\n</header>\n<nav>\n  <a href=\"/courses\">Courses</a>\n  <a href=\"/about\">About</a>\n</nav>\n<main>\n  <article>\n    <h1>Python Fundamentals</h1>\n    <h2>Lesson 1: Variables</h2>\n    <p>Variables store data in memory.</p>\n  </article>\n</main>\n<footer>\n  <p>Copyright 2024 Mabel Academy</p>\n</footer>\n'''\nsemantic_tags=['header','nav','main','article','footer']\ncount=sum(1 for tag in semantic_tags if f'<{tag}>' in html)\nprint(f'Semantic elements used: {count}/{len(semantic_tags)}')\nprint(html)", "hint": "header, nav, main, article, footer are the 5 semantic elements needed.", "rubric": "All 5 semantic tags used. Proper nesting. h1, h2, p inside article. Count shows 5/5."},
      {"title": "HTML Tables & Data Display", "theory": "## HTML Tables\n```python\ntable = '''\n<table>\n  <thead>\n    <tr><th>Name</th><th>Score</th></tr>\n  </thead>\n  <tbody>\n    <tr><td>Ada</td><td>92</td></tr>\n    <tr><td>Tunde</td><td>88</td></tr>\n  </tbody>\n</table>\n'''\n```\nElements: table, thead, tbody, tr (row), th (header cell), td (data cell)", "instructions": "## Task: Dynamic Student Table\n1. Given student data as a list of dicts\n2. Generate an HTML table string dynamically\n3. Include thead with column headers\n4. Include tbody with data rows\n5. Add a tfoot with average score", "starterCode": "students = [\n    {'name': 'Ada', 'course': 'Python', 'score': 92},\n    {'name': 'Tunde', 'course': 'SQL', 'score': 78},\n    {'name': 'Ngozi', 'course': 'AI', 'score': 95},\n]\n\n# Build header\nheaders = students[0].keys()\nheader_row = ''.join(f'<th>{h.title()}</th>' for h in ___)\n\n# Build body rows\nbody_rows = ''\nfor s in students:\n    cells = ''.join(f'<td>{s[h]}</td>' for h in ___)\n    body_rows += f'<tr>{___}</tr>\\n'\n\n# Calculate average\navg = sum(s['score'] for s in ___) / len(students)\n\nhtml = f'''<table>\n  <thead><tr>{header_row}</tr></thead>\n  <tbody>{body_rows}</tbody>\n  <tfoot><tr><td colspan=\"2\">Average</td><td>{avg:.1f}</td></tr></tfoot>\n</table>'''\n\nprint(html)", "solution": "students=[{'name':'Ada','course':'Python','score':92},{'name':'Tunde','course':'SQL','score':78},{'name':'Ngozi','course':'AI','score':95}]\nheaders=students[0].keys()\nheader_row=''.join(f'<th>{h.title()}</th>' for h in headers)\nbody_rows=''\nfor s in students:\n    cells=''.join(f'<td>{s[h]}</td>' for h in headers)\n    body_rows+=f'<tr>{cells}</tr>\\n'\navg=sum(s['score'] for s in students)/len(students)\nhtml=f'''<table>\n  <thead><tr>{header_row}</tr></thead>\n  <tbody>{body_rows}</tbody>\n  <tfoot><tr><td colspan=\"2\">Average</td><td>{avg:.1f}</td></tr></tfoot>\n</table>'''\nprint(html)", "hint": "dict.keys() for headers. Loop dicts for rows. f-string for each cell. sum()/len() for average.", "rubric": "thead with th elements. tbody with dynamic rows. tfoot with average. colspan used."},
      {"title": "HTML Forms & Input Types", "theory": "## HTML Forms\n```python\nform = '''\n<form action=\"/submit\" method=\"POST\">\n  <input type=\"text\" name=\"name\" placeholder=\"Name\" required>\n  <input type=\"email\" name=\"email\" placeholder=\"Email\">\n  <input type=\"number\" name=\"age\" min=\"0\" max=\"120\">\n  <select name=\"level\">\n    <option value=\"beginner\">Beginner</option>\n    <option value=\"advanced\">Advanced</option>\n  </select>\n  <textarea name=\"bio\" rows=\"4\"></textarea>\n  <button type=\"submit\">Submit</button>\n</form>\n'''\n```\nTypes: text, email, password, number, date, checkbox, radio, file, submit", "instructions": "## Task: Registration Form Builder\n1. Build an HTML form string for student registration\n2. Include: text (name), email, password, select (course), textarea (bio)\n3. Add required attribute to name and email\n4. Parse the form to count input elements", "starterCode": "form = f'''\n<form action=\"/register\" method=\"POST\">\n  <label>Name:</label>\n  <input type=\"___\" name=\"name\" placeholder=\"Full Name\" ___>\n  \n  <label>Email:</label>\n  <input type=\"___\" name=\"email\" placeholder=\"you@example.com\" ___>\n  \n  <label>Password:</label>\n  <input type=\"___\" name=\"password\" minlength=\"8\">\n  \n  <label>Course:</label>\n  <select name=\"course\">\n    <option value=\"python\">Python</option>\n    <option value=\"sql\">SQL</option>\n    <option value=\"ai\">___</option>\n  </select>\n  \n  <label>Bio:</label>\n  <textarea name=\"___\" rows=\"4\" placeholder=\"Tell us about yourself\"></textarea>\n  \n  <button type=\"submit\">Register</button>\n</form>\n'''\n\n# Count form elements\ninput_count = form.count('<input')\nselect_count = form.count('<select')\ntextarea_count = form.count('<textarea')\nprint(f'Inputs: {input_count}, Selects: {select_count}, Textareas: {textarea_count}')\nprint(form)", "solution": "form=f'''\n<form action=\"/register\" method=\"POST\">\n  <label>Name:</label>\n  <input type=\"text\" name=\"name\" placeholder=\"Full Name\" required>\n  <label>Email:</label>\n  <input type=\"email\" name=\"email\" placeholder=\"you@example.com\" required>\n  <label>Password:</label>\n  <input type=\"password\" name=\"password\" minlength=\"8\">\n  <label>Course:</label>\n  <select name=\"course\">\n    <option value=\"python\">Python</option>\n    <option value=\"sql\">SQL</option>\n    <option value=\"ai\">AI Engineering</option>\n  </select>\n  <label>Bio:</label>\n  <textarea name=\"bio\" rows=\"4\" placeholder=\"Tell us about yourself\"></textarea>\n  <button type=\"submit\">Register</button>\n</form>\n'''\ninput_count=form.count('<input')\nselect_count=form.count('<select')\ntextarea_count=form.count('<textarea')\nprint(f'Inputs: {input_count}, Selects: {select_count}, Textareas: {textarea_count}')\nprint(form)", "hint": "type='text', type='email', type='password'. required attribute. select with options.", "rubric": "Form with correct action/method. Input types correct. required on name/email. select and textarea present."}
